import React from "react";
import logo from "../assets/logo.png"; // ajusta el path si está en otra carpeta
import { FaComments, FaUserCircle } from "react-icons/fa";

const Header = () => {
  return (
    <header className="w-full flex justify-between items-center px-8 py-4 bg-white shadow">
      <FaComments size={28} />
      <img src={logo} alt="Logo Bicentenario" className="h-16 object-contain" />
      <FaUserCircle size={32} />
    </header>
  );
};

export default Header;
